---@class StructPetDreamLandLotteryData
local StructPetDreamLandLotteryData = LxClass("StructPetDreamLandLotteryData", nil)
function StructPetDreamLandLotteryData:StructPetDreamLandLotteryData()
	---@type number 奖池类型0-普通，1-高级
	self.type = 0

	---@type number 今日已免费抽取次数
	self.freeNum = 0

	---@type number 免费抽奖次数
	self.totalFreeNum = 0

	---@type boolean 是否需要倒计时
	self.needCD = false

	---@type number 下次免费刷新的时间
	self.nextRefreshTimeOfFreeNum = -1

	---@type number 今日已付费抽取次数
	self.payNum = 0

	---@type number 抽取次数上限
	self.totalNum = 0

	---@type table<number> 已领取奖励id
	self.rewardIds = {}

	---@type table<number,boolean> 已领取奖励id Map
	self.rewardIdsMap = {}
end

function StructPetDreamLandLotteryData:CreateByPb(pb)
	self.type = pb.type

	self:SetFreeNum(pb.freeNum)

	self.totalFreeNum = pb.totalFreeNum


	local needCD = false
	self.nextRefreshTimeOfFreeNum = -1
	local freeNumLeft = self.totalFreeNum - self.freeNum
	if freeNumLeft < 1 then
		needCD = true
	end
	self.needCD = needCD

	if freeNumLeft and self.needCD then
		self.nextRefreshTimeOfFreeNum = LUtil.GetNextDayTimes(nil,1)
	end

	self:SetPayNum(pb.payNum)

	self.totalNum = pb.totalNum

	self.rewardIds = {}
	self.rewardIdsMap = {}
	self:SetRewardIds(pb.rewardIds)
end

function StructPetDreamLandLotteryData:SetRewardIds(rewardIds)
	rewardIds = rewardIds or {}
	for i,v in ipairs(rewardIds) do
		if not self.rewardIdsMap[v]  then
			self.rewardIdsMap[v] = true
			table.insert(self.rewardIds,v)
		end
	end
end

function StructPetDreamLandLotteryData:SetFreeNum(freeNum)
	self.freeNum = freeNum
end

function StructPetDreamLandLotteryData:SetPayNum(payNum)
	self.payNum = payNum
end

---@type boolean 是否已经领取
function StructPetDreamLandLotteryData:IsGetRewardId(rewardId)
	return self.rewardIdsMap[rewardId] or false
end

--- 获取当前的进度值
function StructPetDreamLandLotteryData:GetCurGrad()
	local luckyItem = gModelPetDreanLand:GetLuckyItemByLotteryType(self.type)
	if not luckyItem then return 0 end
	return gModelItem:GetNumByRefId(luckyItem.itemId)
end

---@return boolean 判断幸运奖励是否可领取
function StructPetDreamLandLotteryData:CheckLuckHasGet()
	local refs = gModelPetDreanLand:GetPetDreamlandLuckyRefByLottery(self.type)
	if refs and #refs > 0 then
		local curGrad = self:GetCurGrad()
		for i,v in ipairs(refs) do
			if not self:IsGetRewardId(v.refId) then
				if curGrad >= v.grad then
					return true
				end
			end
		end
	end
	return false
end

return StructPetDreamLandLotteryData